import {
    config,
    SetCustomHeader,
    getIdentity,
    getNextCursor,
    newIdentity,
    CheckExtensionVersion,
    UpdateBody,
} from "./common";
import reset_confirmation_modal from "./resetConfirmationModal";
import axios from "axios";

axios.defaults.withCredentials = true;

export default async function getUserInformation(callback) {
    try {
        var load_url = window.location.pathname;
        var username = load_url.split("/")[1];

        let datetime_str = Date.parse(Date().toString());
        config.ref_str = window.btoa(username + datetime_str);
        config.ref_type = "following";
        config.resultUrl = `${config.url}/instagram-${config.ref_type}-result?search=${username}&refer_str=${config.ref_str}`;

        await SetCustomHeader();

        let version_match = await CheckExtensionVersion();

        if (version_match) {
            const URL = `https://www.instagram.com/api/v1/users/web_profile_info/?username=${username}`;

            await axios({
                baseURL: URL,
                method: "GET",
                headers: config.CustomHeaders,
            })
                .then(async (response) => {
                    const userId = response.data.data.user.id;

                    await getIdentity();
                    await getNextCursor();
                    if (
                        config.dataInformation.identity === userId &&
                        config.dataInformation.has_next_page &&
                        config.dataInformation.end_cursor
                    ) {
                        return await reset_confirmation_modal(callback);
                    }
                    await newIdentity(userId);

                    return callback();
                })
                .catch((error) => {
                    console.log(error);
                });
        } else {
            UpdateBody();
        }
    } catch (error) {
        console.error(error);
    }
}
