export async function CheckExtensionVersion() {
    try {
        let response = await axios({
            baseURL: `${api}/extension-version/instagram/`,
            method: "GET",
        });
        return response.data.version === config.version;
    } catch (error) {
        return false;
    }
}

export async function SetCustomHeader() {
    var claim = localStorage.getItem("ins-claim");
    var csrfToken = localStorage.getItem("ins-csrfToken");
    var X_IG_App_ID = localStorage.getItem("ins-X_IG_App_ID");
    var X_ASBD_ID = localStorage.getItem("ins-X_ASBD_ID");

    config.CustomHeaders["x-csrftoken"] = csrfToken;
    config.CustomHeaders["x-ig-www-claim"] = claim;
    config.CustomHeaders["x-asbd-id"] = X_ASBD_ID;
    config.CustomHeaders["x-ig-app-id"] = X_IG_App_ID;
    return 0;
}

export async function newIdentity(identity) {
    config.dataInformation.identity = identity;
    config.dataInformation.end_cursor = null;
    config.dataInformation.has_next_page = null;
    localStorage.setItem(`${config.ref_type}-ins_identity`, identity);
    localStorage.removeItem(`${config.ref_type}-ins_next_cursor`);
    localStorage.removeItem(`${config.ref_type}-ins_has_next`);
    return 0;
}

