export async function waiter() {
    let flag = true;
    for (const key in waiterFlag) {
        if (waiterFlag.hasOwnProperty(key)) {
            flag = flag && waiterFlag[key];
        }
    }

    if (flag) {
        return 0;
    } else {
        await sleep(50);
        return waiter();
    }
}

export function sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function checkdb(URL, user_id) {
    let dbcheck = {};
    if (user_id) {
        dbcheck = {
            message: "False",
        };

        try {
            let data = {};
            data.user_id = user_id;
            data.message = null;
            data.ref_str = config.ref_str;
            data.ref_type = config.ref_type;

            await axios({
                baseURL: URL,
                method: "POST",
                headers: config.headers,
                data: data,
            })
                .then((response) => {
                    dbcheck = response.data;
                    data = {};
                })
                .catch((error) => {
                    data = {};
                });
        } catch (error) {
            console.log(error);
        }
        return dbcheck;
    }

    return dbcheck;
}

export async function reset_scrape_data(callback) {
    localStorage.removeItem(`${config.ref_type}-ins_identity`);
    localStorage.removeItem(`${config.ref_type}-ins_next_cursor`);
    localStorage.removeItem(`${config.ref_type}-ins_has_next`);
    document.querySelector("#reset_modal") &&
        document.querySelector("#reset_modal").remove();
    config.dataInformation.end_cursor = null;
    config.dataInformation.has_next_page = null;
    callback();
    return 0;
}

export async function contiune_with_previous_data(callback) {
    document.querySelector("#reset_modal") &&
        document.querySelector("#reset_modal").remove();
    callback();
    return 0;
}

export function CollectionPlay() {
    config.pause = false;

    document.querySelector(`#${config.ref_type}_play`).style.display = "none";
    document.querySelector(`#${config.ref_type}_pause`).style.display = "flex";
    return 0;
}

export function CollectionPause() {
    config.pause = true;
    document.querySelector(`#${config.ref_type}_pause`).style.display = "none";
    document.querySelector(`#${config.ref_type}_play`).style.display = "flex";
    return 0;
}

export function CollectionCloseBtn() {
    document.querySelector(`#${config.ref_type}_show`).style.display = "none";
    document.querySelector(`#${config.ref_type}_Body`).style.display = "none";
    document.querySelector(`#${config.ref_type}_leadsCount`).innerText = 0;
    document.querySelector(`#${config.ref_type}_ResultBody`) &&
        document.querySelector(`#${config.ref_type}_ResultBody`).remove();
    reset_config();
    window.location.reload();
    return 0;
}

export async function CollectionStop() {
    await setNextCursor();
    config.pause = true;
    config.stop = true;
    document
        .querySelector(`#${config.ref_type}_show`)
        .appendChild(ResultBody());
    document
        .querySelector(`#${config.ref_type}_close`)
        .addEventListener("click", CollectionCloseBtn);
    document.querySelector(`#${config.ref_type}_Body`).style.display = "none";
    document.querySelector(`#${config.ref_type}_ResultBody`).style.display =
        "block";
    return 0;
}

export async function CollectionStart() {
    document.querySelector(`#${config.ref_type}_show`).style.display = "flex";
    document.querySelector(`#${config.ref_type}_Body`).style.display = "block";
    document.querySelectorAll(`[class$="_collection_btn"]`).forEach((item) => {
        item.style.display = "none";
    });
    return 0;
}

export async function setIdentity() {
    localStorage.setItem(
        `${config.ref_type}-ins_identity`,
        config.dataInformation.identity
    );
    return 0;
}

export async function getIdentity() {
    if (localStorage.getItem(`${config.ref_type}-ins_identity`)) {
        config.dataInformation.identity = localStorage.getItem(
            `${config.ref_type}-ins_identity`
        );
    }
    return 0;
}

export async function setNextCursor() {
    localStorage.setItem(
        `${config.ref_type}-ins_next_cursor`,
        config.dataInformation.end_cursor
    );
    localStorage.setItem(
        `${config.ref_type}-ins_has_next`,
        config.dataInformation.has_next_page
    );
    return;
}

export async function getNextCursor() {
    if (localStorage.getItem(`${config.ref_type}-ins_next_cursor`)) {
        config.dataInformation.end_cursor = localStorage.getItem(
            `${config.ref_type}-ins_next_cursor`
        );
    }

    if (localStorage.getItem(`${config.ref_type}-ins_has_next`)) {
        config.dataInformation.has_next_page = JSON.parse(
            localStorage.getItem(`${config.ref_type}-ins_has_next`)
        );
    }

    return 0;
}

export async function newSetNextCursor() {
    localStorage.setItem(`ins-next_max_id`, config.dataInformation.next_max_id);
    localStorage.setItem(`ins-rank_token`, config.dataInformation.rank_token);
    localStorage.setItem(`ins-has_more`, config.dataInformation.has_more);
    return;
}

export async function newGetNextCursor() {
    if (localStorage.getItem(`ins-next_max_id`)) {
        config.dataInformation.next_max_id =
            localStorage.getItem(`ins-next_max_id`);
    }

    if (localStorage.getItem(`ins-rank_token`)) {
        config.dataInformation.rank_token =
            localStorage.getItem(`ins-rank_token`);
    }

    if (localStorage.getItem(`ins-has_next_page`)) {
        config.dataInformation.has_next_page =
            localStorage.getItem(`ins-has_next_page`);
    }

    return 0;
}

