
import { config, setNextCursor } from "./common";


export default async function updateState(){
    try{
        config.dataInformation.end_cursor = config.data.page_info.end_cursor
        config.dataInformation.has_next_page = config.data.page_info.has_next_page
        await setNextCursor()
    }catch(error){
        console.error('updateState error', error);
    }
    return
}