import axios from "axios";
import { config, reset_config } from "./core/common";

import FollowerCollectionButton from "./button/follower";
import FollowingCollectionButton from "./button/following";
import HashtagCollectionButton from "./button/hashtag";
import LocationCollectionButton from "./button/location";
import LikeCollectionButton from "./button/like";
import CommentCollectionButton from "./button/comment";
// import PostCollectionButton from "./button/post";
import SingleProfileCollectionButton from "./button/profile";

axios.defaults.withCredentials = true;

/*----------------- start index.js -------------------------*/

var previous_url = window.location.pathname;

var inserted = true;

function reset_button() {
    reset_config();
    if (document.querySelector(`.follower_collection_btn`) !== null) {
        document.querySelector(`.follower_collection_btn`).remove();
        document.querySelector(`#follower_show`) &&
            document.querySelector(`#follower_show`).remove();
    }

    if (document.querySelector(`.following_collection_btn`) !== null) {
        document.querySelector(`.following_collection_btn`).remove();
        document.querySelector(`#following_show`) &&
            document.querySelector(`#following_show`).remove();
    }

    if (document.querySelector(`.location_collection_btn`) !== null) {
        document.querySelector(`.location_collection_btn`).remove();
        document.querySelector(`#location_show`) &&
            document.querySelector(`#location_show`).remove();
    }

    if (document.querySelector(`.hashtag_collection_btn`) !== null) {
        document.querySelector(`.hashtag_collection_btn`).remove();
        document.querySelector(`#hashtag_show`) &&
            document.querySelector(`#hashtag_show`).remove();
    }

    if (document.querySelector(".like_collection_btn") !== null) {
        document.querySelector(".like_collection_btn").remove();
        document.querySelector("#like_show") &&
            document.querySelector("#like_show").remove();
    }

    if (document.querySelector(".comment_collection_btn") !== null) {
        document.querySelector(".comment_collection_btn").remove();
        document.querySelector("#comment_show") &&
            document.querySelector("#comment_show").remove();
    }

    if (document.querySelector(".profile_collection_btn") !== null) {
        document.querySelector(".profile_collection_btn").remove();
        document.querySelector(".single_profile_collection_btn") &&
            document.querySelector(".single_profile_collection_btn").remove();
        document.querySelector("#profile_show") &&
            document.querySelector("#profile_show").remove();
    }

    inserted = true;
}

function GetSearchValue() {
    let url = window.location.href;

    if (previous_url !== url) {
        reset_button();
        previous_url = url;

        if (inserted && url.match("/followers") !== null) {
            FollowerCollectionButton("follower");
            inserted = false;
            return 0;
        }

        if (inserted && url.match("/following") !== null) {
            FollowingCollectionButton("following");
            inserted = false;
            return 0;
        }

        if (
            inserted &&
            (url.match("/tags/") !== null ||
                url.match("/explore/search/keyword/") !== null)
        ) {
            if (url.match("/explore/search/keyword/") !== null) {
                config.new_version = true;
            }
            HashtagCollectionButton("hashtag");
            inserted = false;
            return 0;
        }

        if (inserted && url.match("/locations/") !== null) {
            LocationCollectionButton("location");
            inserted = false;
            return 0;
        }

        if (inserted && url.match(/p\/+[A-Za-z0-9]*/g) !== null) {
            // LikeCollectionButton("like");
            CommentCollectionButton("comment");
            inserted = false;
            return 0;
        }

        if (
            inserted &&
            url.match(/instagram.com\/[A-Za-z0-9_.]*\/$/g) !== null &&
            url.match("/explore/") === null
        ) {
            SingleProfileCollectionButton();
            // PostCollectionButton("profile");
            inserted = false;
            return 0;
        }
    }

    return 0;
}

function Check_leads() {
    let inter = setInterval(function () {
        clearInterval(inter);
        Check_leads();

        return GetSearchValue();
    }, 1000);
}

Check_leads();

/*----------------- end popup.js -------------------------*/
