import {
    config,
    CollectionStop,
    } from "./common";

export function ManyRequestCollectionCloseBtn(){
	document.querySelector(`#sss_${config.ref_type}_ResultBody`).remove();
	return 0;
}

export async function ManyRequestCollectionStop(){
    // CollectionStop()
    config.pause = true;
	config.stop = true;
	document.querySelector(`#${config.ref_type}_show`).appendChild(ManyRequestPopUp())
 	document.querySelector(`#sss_${config.ref_type}_close`).addEventListener("click", ManyRequestCollectionCloseBtn)
	document.querySelector(`#sss_${config.ref_type}_ResultBody`).style.display = 'block';

	return 0;
}


export function ManyRequestPopUp() {

	var Inhtml = `
			<div id="sss_${config.ref_type}_ResultBody" class="result_body" style="display: block;z-index: 999999;">
				<div class="Body-div">
				<div class="leadstal-header">
					<span class="header-title">Warning by LeadStal</span>
					<div class="close-btn" style='float: right;' aria-label="Close" id="sss_${config.ref_type}_close">
						<span aria-hidden="true">&times;</span>
					</div>
				</div>
					<div class="result-content" style="height: 150px;">
						<p style="padding: 50px 15px;">Too many data you are scraping today. try again next day</p>
					</div>
					<div class="leadstal-footer"></div>
				</div>
			</div>
			`;

			var div = document.createElement('div');
			div.innerHTML = Inhtml.trim();

			return div.firstChild;
}