import {
    config,
    checkdb,
    waiter,
    } from "./common";
import calculateAverage from './calculateAverage';
import setData from './setData';
import getUserPost from './getUserPost';
import getUserProfile from './getUserProfile';


export async function APICallerVTwo(user_id){
    let URL = `${config.api}/instagram/${config.ref_type}_profile_filter/`;

	let dbcheck = await checkdb(URL, user_id);

	if(dbcheck.message === null || dbcheck.message === undefined){
		config.data_object = {};
		// console.error('APICaller error invalid user_id', user_id);
		return 
	}

	if( dbcheck.message === 'False' ){
		getUserProfile(user_id);
		// getUserPost(user_id);
		await waiter();
		await calculateAverage();
	}

	return 0;
}

export async function saveData(){

    let API_URL = `${config.api}/instagram/${config.ref_type}_create/`;

	await setData(API_URL);
	return 0;
}