import {
    sleep,
    config,
    CollectionStop,
    } from "./common";

import {APICallerVTwo, saveData} from "./apiCallerVTwo";


export default async function parsePostInformation(callback){
	config.data_object.ref_str = config.ref_str;
	config.data_object.ref_type = config.ref_type;
	config.data_object.location = config.dataInformation.location;

	if(config.stop){
		return CollectionStop();
	}

	if(!config.pause){

		if(config.position >= config.data.edges.length){
			if(config.dataInformation.has_next_page){
				config.position = 0;
				return callback();
			}
			return CollectionStop();
		}

		let post = config.data.edges[config.position].node;
		let caption = post.edge_media_to_caption.edges.length > 0 ? post.edge_media_to_caption.edges[0].node.text : "";


		config.data_object.user_id = post.owner.id;
		config.data_object.thumbnail_url = post.thumbnail_src;
		config.data_object.display_url = post.display_url;
		config.data_object.like_count = post.edge_media_preview_like.count <= 0 ? 0 : post.edge_media_preview_like.count;
		config.data_object.post_comment = post.edge_media_to_comment.count <= 0 ? 0 : post.edge_media_to_comment.count;
		config.data_object.post_caption = (caption === null && caption === '') ? null : caption;
		config.data_object.timestamp = post.taken_at_timestamp;
		config.data_object.shortcode = post.shortcode;
		config.data_object.is_video = post.is_video;
		config.data_object.is_paid_partnership = (post.is_paid_partnership === undefined) ? false : post.is_paid_partnership;
		config.data_object.video_url = post.video_url;
		config.data_object.video_view_count = post.video_view_count;

        await APICallerVTwo(post.owner.id);

		let like = post.edge_media_preview_like.count <= 0 ? 0 : post.edge_media_preview_like.count;
		let comment = post.edge_media_to_comment.count <= 0 ? 0 : post.edge_media_to_comment.count;
		let engagement_rate = (like + comment) <= 0 ? 0 : ((like + comment)/config.data_object.follower_count*100).toFixed(10);
		
		config.data_object.engagement_rate_post = (engagement_rate === 'NaN' ? null : engagement_rate);

        await saveData();

		config.position++;
		return parsePostInformation(callback);
	}else{
		await sleep(100);
		return parsePostInformation(callback);
	}
}
