import { config } from "./common";
import axios from "axios";

export default async function setData(URL) {
    if (config.data_object.user_id) {
        try {
            await axios({
                baseURL: URL,
                method: "POST",
                headers: config.headers,
                data: config.data_object,
            })
                .then((response) => {
                    document.getElementById(
                        `${config.ref_type}_leadsCount`
                    ).innerText = ++config.totalLeads;
                    config.data_object = {};
                })
                .catch((error) => {
                    console.error(error);
                    config.data_object = {};
                });
        } catch (error) {
            console.error(error);
        }
        return;
    }

    config.data_object = {};
    return;
}
