
import reset_modal_body from './resetModalBody';
import { 
    reset_scrape_data,
    contiune_with_previous_data 
} from './common';



export default async function resetConfirmationModal(callback){
    
    try {
		var reset_modal = document.createElement('div');
		reset_modal.id = 'reset_modal';
		reset_modal.className = 'container leadstal-show';
		document.body.appendChild(reset_modal);
		reset_modal.appendChild(reset_modal_body());

		var blocker = document.createElement('div');
		blocker.id = 'screenOff';
		blocker.className = 'screen-off';
		reset_modal.appendChild(blocker);


		document.querySelector("#continue_button").addEventListener("click", () => contiune_with_previous_data(callback));
		document.querySelector("#reset_button").addEventListener("click", () => reset_scrape_data(callback));

	} catch (error) {
        console.error(error);
		// save_error(JSON.stringify(error, Object.getOwnPropertyNames(error)))
	}
	
}
