import axios from "axios";
import {
    sleep,
    config,
    SetCustomHeader,
    CollectionStop,
    CollectionPlay,
    CollectionPause,
    CollectionStart,
    setIdentity,
    getIdentity,
    getNextCursor,
    ContentBody,
    newIdentity,
    newGetNextCursor,
    CheckExtensionVersion,
    UpdateBody,
} from "../core/common";
import { ManyRequestCollectionStop } from "../core/ManyRequest";
import reset_confirmation_modal from "../core/resetConfirmationModal";
import updateState from "../core/updateState";
import getUserProfile from "../core/getUserProfile";
import { APICallerVTwo, saveData } from "../core/apiCallerVTwo";

axios.defaults.withCredentials = true;

/*----------------- start Hashtag.js -------------------------*/

async function startScrapingForHashtag() {
    let load_url = window.location.pathname;
    let hashtag = undefined;
    let keyword = undefined;
    // let regex = new RegExp("tags");
    if (load_url.match("/tags/") !== null) {
        load_url = load_url.split("/");
        hashtag = load_url[load_url.length - 2];
    } else if (load_url.match("/explore/search/keyword/") !== null) {
        load_url = decodeURIComponent(window.location.href);
        load_url = load_url.split("?q=");
        hashtag = load_url[1];
        keyword = hashtag.replace("#", "");
    }

    let datetime_str = Date.parse(Date().toString());
    config.ref_str = window.btoa(keyword + datetime_str);
    config.ref_type = "hashtag";
    config.resultUrl = `${config.url}/instagram-${config.ref_type}-result?search=${keyword}&refer_str=${config.ref_str}`;

    let version_match = await CheckExtensionVersion();

    if (version_match) {
        if (config.new_version) {
            // await newGetNextCursor();
            CollectionStart();
            return newVersionGetPost();
        } else {
            await getIdentity();
            await getNextCursor();

            if (
                config.dataInformation.identity === hashtag &&
                config.dataInformation.has_next_page &&
                config.dataInformation.end_cursor
            ) {
                return await reset_confirmation_modal(letsStart);
            }

            await newIdentity(hashtag);

            return letsStart();
        }
    } else {
        UpdateBody();
    }
}

let scroller = 0;
async function startAutoScroll() {
    try {
        scroller += 100;
        $("html").animate({ scrollTop: scroller }, 1000);
    } catch (error) {
        console.log("error", error);
        return;
    }
}

async function getData() {
    let data = localStorage.getItem("ins-data");
    if (data === null) {
        await startAutoScroll();
        await sleep(1000);
        return getData();
    }
    data = JSON.parse(data);
    return data;
}

async function newVersionGetPost() {
    await SetCustomHeader();

    let data = await getData();
    await newGetNextCursor();
    localStorage.removeItem("ins-data");
    await newParserPostInformation(data);
    return;
}

async function newParserPostInformation(data) {
    if (config.stop) {
        return CollectionStop();
    }

    if (!config.pause) {
        if (data.length <= 0) {
            if (config.dataInformation.has_next_page) {
                return newVersionGetPost();
            }
            return CollectionStop();
        }

        let post = data.pop();
        console.log("newparserPostInformation post", post);
        post = post.media;
        config.data_object.ref_str = config.ref_str;
        config.data_object.ref_type = config.ref_type;
        config.data_object.user_id = post.owner.id;
        config.data_object.thumbnail_url =
            post.image_versions2 && post.image_versions2.candidates
                ? post.image_versions2.candidates[
                      post.image_versions2.candidates.length - 1
                  ].url
                : null;
        config.data_object.like_count = 0;
        config.data_object.post_caption = post.caption
            ? post.caption.text
            : null;
        config.data_object.timestamp = post.caption
            ? post.caption.created_at
            : null;
        config.data_object.shortcode = post.code;
        config.data_object.is_video = post.hasOwnProperty('video_duration');
        config.data_object.is_paid_partnership =
            post.is_paid_partnership === undefined ||
            post.is_paid_partnership === false
                ? false
                : post.is_paid_partnership;
        config.data_object.video_url = post.video_versions
            ? post.video_versions[0].url
            : null;
        config.data_object.video_view_count = post.view_count;

        config.data_object.display_url = config.data_object.thumbnail_url;
        config.data_object.post_comment = 0;
        config.data_object.engagement_rate_post = 0;

        console.log("newparserPostInformation config.data_object", config.data_object);

        await getUserProfile(post.owner.id);
        await saveData();

        config.position++;
        return newParserPostInformation(data);
    } else {
        await sleep(100);
        return newParserPostInformation(data);
    }
}

async function letsStart() {
    CollectionStart();
    return await getPost();
}

async function getPost() {
    await setIdentity();
    await getNextCursor();
    await SetCustomHeader();

    if (config.stop) {
        return CollectionStop();
    }

    let paramString = {
        tag_name: config.dataInformation.identity,
        first: 50,
        after: config.dataInformation.end_cursor,
    };

    let params = {
        query_hash: config.QueryHashForHashtag,
        variables: JSON.stringify(paramString),
    };

    let URL = "https://www.instagram.com/graphql/query/";

    if (!config.pause) {
        await axios({
            baseURL: URL,
            method: "GET",
            headers: config.CustomHeaders,
            params: params,
        })
            .then(async (response) => {
                console.log("Hashtag data fetched");
                config.data = response.data.data.hashtag.edge_hashtag_to_media;
                console.log("config.data", config.data);
                await updateState();
                await parsePostInformation();
            })
            .catch((error) => {
                if (error.response.status === 429) {
                    ManyRequestCollectionStop();
                }
            });
    } else {
        await sleep(100);
        return getPost();
    }
}

async function parsePostInformation() {
    config.data_object.ref_str = config.ref_str;
    config.data_object.ref_type = config.ref_type;
    config.data_object.hashtag = config.dataInformation.identity;

    if (config.stop) {
        return CollectionStop();
    }

    if (!config.pause) {
        if (config.position >= config.data.edges.length) {
            if (config.dataInformation.has_next_page) {
                config.position = 0;
                return getPost();
            }
            return CollectionStop();
        }

        let post = config.data.edges[config.position].node;
        console.log("Processing post:", config.position + 1);
        console.log("post", post);
        let caption =
            post.edge_media_to_caption.edges.length > 0
                ? post.edge_media_to_caption.edges[0].node.text
                : "";

        config.data_object.user_id = post.owner.id;
        config.data_object.thumbnail_url = post.thumbnail_src;
        config.data_object.display_url = post.display_url;
        config.data_object.like_count =
            post.edge_media_preview_like.count <= 0
                ? 0
                : post.edge_media_preview_like.count;
        config.data_object.post_comment =
            post.edge_media_to_comment.count <= 0
                ? 0
                : post.edge_media_to_comment.count;
        config.data_object.post_caption =
            caption === null && caption === "" ? null : caption;
        config.data_object.timestamp = post.taken_at_timestamp;
        config.data_object.shortcode = post.shortcode;
        config.data_object.is_video = post.is_video;
        config.data_object.is_paid_partnership =
            post.is_paid_partnership === undefined
                ? false
                : post.is_paid_partnership;
        config.data_object.video_url = post.video_url;
        config.data_object.video_view_count = post.video_view_count;

        let like =
            post.edge_media_preview_like.count <= 0
                ? 0
                : post.edge_media_preview_like.count;
        let comment =
            post.edge_media_to_comment.count <= 0
                ? 0
                : post.edge_media_to_comment.count;

        await APICallerVTwo(post.owner.id);

        let engagement_rate =
            like + comment <= 0
                ? 0
                : (
                      ((like + comment) / config.data_object.follower_count) *
                      100
                  ).toFixed(10);

        config.data_object.engagement_rate_post =
            engagement_rate === "NaN" ? null : engagement_rate;

        await saveData();
        config.position++;
        return parsePostInformation();
    } else {
        await sleep(100);
        return parsePostInformation();
    }
}

export default function collectionButton(button_type) {
    config.ref_type = button_type;
    try {
        var leadstalButton = document.createElement("div");
        leadstalButton.className = `${config.ref_type}_collection_btn`;
        leadstalButton.innerHTML = `<img id="icon" class="btn-icon" src="${config.fav_icon}" alt=""></img> <p class="text">${config.ref_type} Leads</p>`;

        document.body.appendChild(leadstalButton);

        var leadstaShow = document.createElement("div");
        leadstaShow.id = `${config.ref_type}_show`;
        leadstaShow.className = "container leadstal-show";
        leadstaShow.style.display = "none";
        document.body.appendChild(leadstaShow);
        leadstaShow.appendChild(ContentBody());

        var blocker = document.createElement("div");
        blocker.id = "screenOff";
        blocker.className = "screen-off";
        leadstaShow.appendChild(blocker);

        document
            .querySelector(`#${config.ref_type}_play_btn`)
            .addEventListener("click", CollectionPlay);
        document
            .querySelector(`#${config.ref_type}_pause_btn`)
            .addEventListener("click", CollectionPause);
        document
            .querySelector(`#${config.ref_type}_stop_btn`)
            .addEventListener("click", CollectionStop);
        document
            .querySelector(`.${config.ref_type}_collection_btn`)
            .addEventListener("click", startScrapingForHashtag);
    } catch (error) {
        console.log(error);
    }
}

