import {
    sleep,
    config,
    SetCustomHeader,
    checkdb,
    waiter,
    CollectionStop,
    CollectionPlay,
    CollectionPause,
    CollectionStart,
    getNextCursor,
    ContentBody,
    getIdentity,
    setIdentity,
    newIdentity,
    CheckExtensionVersion,
    UpdateBody,
} from "../core/common";
import { ManyRequestCollectionStop } from "../core/ManyRequest";
import reset_confirmation_modal from "../core/resetConfirmationModal";
import calculateAverage from "../core/calculateAverage";
import setData from "../core/setData";
import getUserPost from "../core/getUserPost";
import getUserProfile from "../core/getUserProfile";
import updateState from "../core/updateState";

import axios from "axios";

axios.defaults.withCredentials = true;

/*----------------- start followers.js -------------------------*/

async function getUserInformation() {
    try {
        var load_url = window.location.pathname;
        var username = load_url.split("/")[1];

        let datetime_str = Date.parse(Date().toString());
        config.ref_str = window.btoa(username + datetime_str);
        config.ref_type = "follower";
        config.resultUrl = `${config.url}/instagram-follower-result?search=${username}&refer_str=${config.ref_str}`;

        await SetCustomHeader();

        let version_match = await CheckExtensionVersion();

        if (version_match) {
            const URL = `https://www.instagram.com/api/v1/users/web_profile_info/?username=${username}`;

            await axios({
                baseURL: URL,
                method: "GET",
                headers: config.CustomHeaders,
            })
                .then(async (response) => {
                    const userId = response.data.data.user.id;
                    await getIdentity();
                    await getNextCursor();
                    if (
                        config.dataInformation.identity === userId &&
                        config.dataInformation.has_next_page &&
                        config.dataInformation.end_cursor
                    ) {
                        return await reset_confirmation_modal(start_scrap);
                    }
                    await newIdentity(userId);
                    start_scrap();
                })
                .catch((error) => {
                    console.log(error);
                    if (error.response.status === 429) {
                        ManyRequestCollectionStop();
                    }
                });
        } else {
            UpdateBody();
        }
    } catch (error) {
        console.error(error);
    }

    return 0;
}

async function start_scrap() {
    await setIdentity();
    await CollectionStart();
    getList();
    return 0;
}

async function getList() {
    try {
        if (config.stop) {
            return CollectionStop();
        }
        await getNextCursor();
        await SetCustomHeader();

        let paramString = {
            id: config.dataInformation.identity,
            first: 50,
            after: config.dataInformation.end_cursor,
        };

        let params = {
            query_hash: config.QueryHashFollowers,
            variables: JSON.stringify(paramString),
        };
        // console.log('query params', params);
        let URL = "https://www.instagram.com/graphql/query/";

        if (!config.pause) {
            await axios({
                baseURL: URL,
                method: "GET",
                headers: config.CustomHeaders,
                params: params,
            })
                .then((response) => {
                    config.data = response.data.data.user.edge_followed_by;
                    updateState();
                    pushData();
                })
                .catch((error) => {
                    if (error.response.status === 429) {
                        ManyRequestCollectionStop();
                    }
                });
        } else {
            await sleep(100);
            return getList();
        }
    } catch (error) {
        console.error(error);
    }
}

async function pushData() {
    try {
        // await getPosition();
        config.data_object.ref_str = config.ref_str;
        config.data_object.ref_type = config.ref_type;

        if (config.stop) {
            return CollectionStop();
        }

        if (!config.pause) {
            if (config.position >= config.data.edges.length) {
                if (config.dataInformation.has_next_page) {
                    config.position = 0;
                    return getList();
                }
                return CollectionStop();
            }

            let user = config.data.edges[config.position].node;

            await APICaller(user.id);
            config.position++;
            return pushData();
        } else {
            await sleep(100);
            return pushData();
        }
    } catch (error) {
        console.error(error);
    }
}

async function APICaller(user_id) {
    try {
        let URL = `${config.api}/instagram/follower_profile_filter/`;

        let dbcheck = await checkdb(URL, user_id);

        if (dbcheck.message === null || dbcheck.message === undefined) {
            config.data_object = {};
            // console.error('APICaller error invalid user_id', user_id);
            return;
        }

        if (dbcheck.message === "False") {
            getUserProfile(user_id);
            // getUserPost(user_id);

            await waiter();
            await calculateAverage();
            let API_URL = `${config.api}/instagram/follower_create/`;

            await setData(API_URL);
        } else {
            document.querySelector(`#${config.ref_type}_leadsCount`).innerText =
                ++config.totalLeads;
            config.data_object = {};
        }
    } catch (error) {
        config.data_object = {};
        console.error("APICaller error", error);
    }

    return 0;
}

export default function collectionButton(button_type) {
    config.ref_type = button_type;
    try {
        var leadstalButton = document.createElement("div");
        leadstalButton.className = `${config.ref_type}_collection_btn`;
        leadstalButton.innerHTML = `<img id="icon" class="btn-icon" src="${config.fav_icon}" alt=""></img> <p class="text">${config.ref_type} Leads</p>`;

        document.body.appendChild(leadstalButton);

        var leadstaShow = document.createElement("div");
        leadstaShow.id = `${config.ref_type}_show`;
        leadstaShow.className = "container leadstal-show";
        leadstaShow.style.display = "none";
        document.body.appendChild(leadstaShow);
        leadstaShow.appendChild(ContentBody());

        var blocker = document.createElement("div");
        blocker.id = "screenOff";
        blocker.className = "screen-off";
        leadstaShow.appendChild(blocker);

        document
            .querySelector(`#${config.ref_type}_play_btn`)
            .addEventListener("click", CollectionPlay);
        document
            .querySelector(`#${config.ref_type}_pause_btn`)
            .addEventListener("click", CollectionPause);
        document
            .querySelector(`#${config.ref_type}_stop_btn`)
            .addEventListener("click", CollectionStop);
        document
            .querySelector(`.${config.ref_type}_collection_btn`)
            .addEventListener("click", getUserInformation);
    } catch (error) {
        console.error("collection_button error", error);
        // save_error(JSON.stringify(error, Object.getOwnPropertyNames(error)))
    }
}

/*----------------- end followers.js -------------------------*/
