import {
    sleep,
    config,
    waiterFlag,
    CollectionStop,
    } from "./common";

import {
    ManyRequestCollectionStop
    } from "./ManyRequest";
import axios from "axios";


export default async function getUserProfile(user_id){
    try{
        if(config.stop){
            return CollectionStop();
        }

        let URL = `https://i.instagram.com/api/v1/users/${user_id}/info/`;

        if(!config.pause){

            waiterFlag['profile'] = false;

            await axios({
                baseURL: URL,
                method: "GET",
                headers: config.CustomHeaders
            })
            .then((response) => {
                let data = response.data.user;

                config.data_object.biography = (data.biography === null || data.biography === '') ? null : data.biography;
                config.data_object.username = data.username;
                config.data_object.full_name = data.full_name;
                config.data_object.external_url = (data.external_url === null || data.external_url === '') ? null : data.external_url;
                config.data_object.follower_count = data.follower_count;
                config.data_object.following_count = data.following_count;
                config.data_object.following_tag_count = data.following_tag_count;
                config.data_object.has_videos = data.has_videos;
                config.data_object.hd_profile_pic_url = ( data.hd_profile_pic_url_info === null ? null : data.hd_profile_pic_url_info.url );
                config.data_object.is_business = data.is_business;
                config.data_object.is_private = data.is_private;
                config.data_object.is_verified = data.is_verified;
                config.data_object.media_count = (data.media_count === null || data.media_count === '') ? null : data.media_count;
                config.data_object.user_id = data.pk;
                config.data_object.profile_pic_url = (data.profile_pic_url === null || data.profile_pic_url === '') ? null : data.profile_pic_url;
                config.data_object.total_igtv_videos = data.total_igtv_videos;
                config.data_object.usertags_count = (data.usertags_count === null || data.usertags_count === '') ? null : data.usertags_count;
                config.data_object.city_name = (data.city_name === null || data.city_name === '') ? null : data.city_name;
                config.data_object.public_email = (data.public_email === null || data.public_email === '') ? null : data.public_email;
                config.data_object.contact_phone_number = (data.contact_phone_number === null || data.contact_phone_number === '') ? null : data.contact_phone_number;
                config.data_object.total_clips_count = (data.total_clips_count === null || data.total_clips_count === '') ? null : data.total_clips_count;
                waiterFlag['profile'] = true;
            })
            .catch((error) => {
                if(error.response.status === 429){
                    ManyRequestCollectionStop()
                }

                waiterFlag['profile'] = true;
            });
        }else{
            await sleep(100);
            return getUserProfile(user_id);
        }
    }catch(error){
        console.error( error )
    }
    return 0;
}