import {
    config,
    } from "./common";
    
export default async function calculateAverage(){
	try{
        if(config.post_data){
            let post_length = config.post_data.edges.length;
            let likes = 0;
            let comments = 0;
            
    
            config.post_data.edges.forEach(item => {
                likes += item.node.edge_media_preview_like.count <= 0 ? 0 : item.node.edge_media_preview_like.count;
                comments += item.node.edge_media_to_comment.count <= 0 ? 0 : item.node.edge_media_to_comment.count;
            });
    
    
            let average_likes = (likes <= 0 ? 0 : likes/post_length);
            let average_comments = (comments <= 0 ? 0 : comments/post_length);
    
            let engagement_rate = (average_likes + average_comments) <= 0 ? 0 : ((average_likes + average_comments)/config.data_object.follower_count*100).toFixed(10);
            config.data_object.engagement_rate = (engagement_rate === 'NaN' ? null : engagement_rate);
            config.data_object.average_likes = Math.round(average_likes);
            config.data_object.average_comments = Math.round(average_comments);
            config.data_object.est_min_post_price = Math.round((config.data_object.average_likes + config.data_object.average_comments) * 0.12);
            config.data_object.est_max_post_price = Math.round((config.data_object.average_likes + config.data_object.average_comments) * 0.18);
            config.data_object.est_min_story_price = Math.round((config.data_object.average_likes + config.data_object.average_comments) * 0.05);
            config.data_object.est_max_story_price = Math.round((config.data_object.average_likes + config.data_object.average_comments) * 0.09);
        }
        
    }catch(error){
        console.error(error)
    }
	return 0;
}