
import {
    sleep,
    config,
    CollectionStop,
    } from "./common";
import APICaller from './apiCaller';


export default async function pushData(callback){
	try{
        config.data_object.ref_str = config.ref_str;
        config.data_object.ref_type = config.ref_type;
        
        if(config.stop){
            return CollectionStop();
        }

        if(!config.pause){

            if(config.position >= config.data.edges.length){
                if(config.dataInformation.has_next_page){
                    config.position = 0;
                    return callback();
                }
                return CollectionStop();
            }

            let user = config.data.edges[config.position].node;

            await APICaller(user.id);

            config.position++;
            return pushData(callback);
        }else{
            await sleep(100);
            return pushData(callback);
        }
    }catch(error){
        console.error(error);
    }
}