import axios from "axios";
import {
    config,
    SetCustomHeader,
    CheckExtensionVersion,
    UpdateBody,
} from "../core/common";
import calculateAverage from "../core/calculateAverage";
import getUserProfile from "../core/getUserProfile";
import getUserPost from "../core/getUserPost";

axios.defaults.withCredentials = true;

/*----------------- start SingleProfile.js -------------------------*/

async function getUserInformation() {
    let load_url = window.location.pathname;
    let username = load_url.split("/")[1];
    config.dataInformation.username = username;

    let datetime_str = Date.parse(Date().toString());
    config.ref_str = window.btoa(username + datetime_str);
    config.ref_type = "single-profile";
    config.resultUrl = `${config.url}/instagram-single-profile-result?search=${username}&refer_str=${config.ref_str}`;

    await SetCustomHeader();

    let version_match = await CheckExtensionVersion();

    if (version_match) {
        const URL = `https://www.instagram.com/api/v1/users/web_profile_info/?username=${username}`;

        await axios({
            baseURL: URL,
            method: "GET",
            headers: config.CustomHeaders,
        })
            .then((response) => {
                config.dataInformation.identity = response.data.data.user.id;
                config.dataInformation.follower =
                    response.data.data.user.edge_followed_by.count;
                config.dataInformation.following =
                    response.data.data.user.edge_follow.count;

                userInformationForSingleProfile(
                    config.dataInformation.identity
                );
            })
            .catch((error) => {
                console.log(error);
            });
    } else {
        UpdateBody();
    }
}

async function userInformationForSingleProfile(user_id) {
    await getUserProfile(user_id);
    // await getUserPost(user_id);
    await calculateAverage();

    await updateSingleProfile();

    return 0;
}

async function updateSingleProfile() {
    let URL = `${config.api}/instagram/single_profile_create/`;
    config.data_object.ref_str = config.ref_str;
    config.data_object.ref_type = config.ref_type;

    await axios({
        baseURL: URL,
        method: "POST",
        headers: config.headers,
        data: config.data_object,
    })
        .then((response) => {
            let data = response.data;

            if (data.public_email || data.contact_phone_number) {
                Single_Profile_result_button_with_email();
            } else {
                Single_Profile_result_button_without_email();
            }

            config.data_object = {};
        })
        .catch((error) => {
            console.error(error);
        });
    return 0;
}

export default function Single_Profile_collection_button() {
    try {
        var leadstalButton = document.createElement("div");
        leadstalButton.className = "single_profile_collection_btn";
        leadstalButton.innerHTML = `<img id="icon" class="btn-icon" src="${config.fav_icon}"></img>
				<p class="text">Profile Lead</p>`;
        document.body.appendChild(leadstalButton);
        getUserInformation();
    } catch (error) {
        console.error(error);
    }
    return 0;
}

function Single_Profile_result_button_without_email() {
    try {
        document.querySelector(".single_profile_collection_btn") &&
            document.querySelector(".single_profile_collection_btn").remove();
        var leadstalButton = document.createElement("div");
        leadstalButton.className = "single_profile_collection_btn";
        leadstalButton.innerHTML = `<a href="${config.resultUrl}" target="_blank">
				<img id="icon" class="btn-icon" src="${config.fav_icon}"></img>
				<p class="text">Profile Lead</p>
				</a>`;
        document.body.appendChild(leadstalButton);
    } catch (error) {
        console.error(error);
    }
    return 0;
}

function Single_Profile_result_button_with_email() {
    try {
        document.querySelector(".single_profile_collection_btn") &&
            document.querySelector(".single_profile_collection_btn").remove();
        var leadstalButton = document.createElement("div");
        leadstalButton.className = "single_profile_collection_btn";
        leadstalButton.innerHTML = `<a href="${config.resultUrl}" target="_blank">
				<img id="icon" class="btn-icon" src="${config.fav_icon}"></img>
				<p class="text">Profile Lead</p>
				<img id="mail-icon" class="mail-btn-icon" src="${config.mail_icon}"></img>
				</a>`;
        document.body.appendChild(leadstalButton);
    } catch (error) {
        console.error(error);
    }
    return 0;
}

/*----------------- end SingleProfile.js -------------------------*/
