import axios from "axios";
import {
    config, 
    SetCustomHeader,
    } from "./common";


axios.defaults.withCredentials = true;


export default async function getUsername(){
	let username = 'profile';

	await SetCustomHeader();

	let URL = window.location.pathname;

	await axios({
		baseURL: URL,
		method: "GET",
		headers: config.CustomHeaders
	})
	.then((response) => {
		let string_html = response.data;
		let parser = new DOMParser();
		let content = parser.parseFromString(string_html, 'text/html');

		content = content.head;
		let title = content.querySelector('meta[name="twitter:title"]').content;
		title = title.split('(@')[1];

		username = title.split(')')[0];
		
	})
	.catch((error) => {
        console.log(error);
	});
	return username;
}